export async function migrateControlServiceDatabase(databaseOptions: unknown) {
  const databaseConfig = validatePostgresLifecycleConfig(databaseOptions);
  if (databaseConfig.profile !== "production")
    throw new Error("production_database_profile_required");
  const database = createPostgresLifecycleDatabase({ config: databaseConfig });
  try {
    return await migratePostgresLifecycleSchema({
      executor: database.migrationExecutor,
      owner: database.schemaOwner,
      schema: database.schema,
    });
  } finally {
    await database.close();
  }
}

